class Solution {
    public double minTime(int n, int k, int m, int[] time, double[] mul) {
        if (k == 1 && n > 1) {
            return -1;
        }

        int[][] dp = new int[n + 1][1 << n];
        double[][] dpTime = new double[n + 1][1 << n];
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j < (1 << n); j++) {
                dpTime[i][j] = Double.POSITIVE_INFINITY;
            }
        }
        dp[0][0] = 0;
        dpTime[0][0] = 0;

        for (int i = 0; i <= n; i++) {
            for (int mask = 0; mask < (1 << n); mask++) {
                if (dp[i][mask] == 0) continue;
                for (int groupSize = 1; groupSize <= k; groupSize++) {
                    for (int groupMask = 0; groupMask < (1 << n); groupMask++) {
                        if ((groupMask & mask) != 0 || Integer.bitCount(groupMask) != groupSize) continue;
                        int newMask = mask | groupMask;
                        double crossTime = 0;
                        for (int j = 0; j < n; j++) {
                            if ((groupMask & (1 << j)) != 0) {
                                crossTime = Math.max(crossTime, time[j]);
                            }
                        }
                        int currentStage = dp[i][mask] % m;
                        crossTime *= mul[currentStage];
                        double totalTime = dpTime[i][mask] + crossTime;
                        int newStage = (dp[i][mask] + (int) Math.floor(crossTime)) % m;
                        if (newMask == (1 << n) - 1) {
                            dpTime[n][newMask] = Math.min(dpTime[n][newMask], totalTime);
                        } else {
                            for (int returnPerson = 0; returnPerson < n; returnPerson++) {
                                if ((newMask & (1 << returnPerson)) != 0) {
                                    double returnTime = time[returnPerson] * mul[newStage];
                                    totalTime += returnTime;
                                    newStage = (newStage + (int) Math.floor(returnTime)) % m;
                                    dpTime[i + 1][newMask ^ (1 << returnPerson)] = Math.min(dpTime[i + 1][newMask ^ (1 << returnPerson)], totalTime);
                                    dp[i + 1][newMask ^ (1 << returnPerson)] = newStage;
                                }
                            }
                        }
                    }
                }
            }
        }
        return dpTime[n][(1 << n) - 1] == Double.POSITIVE_INFINITY ? -1 : dpTime[n][(1 << n) - 1];
    }
}
